syntax = "proto3";

package envoy.extensions.filters.http.custom_header_injection.v3;

import "google/protobuf/struct.proto";
import "udpa/annotations/status.proto";
import "validate/validate.proto";

option java_package = "io.envoyproxy.envoy.extensions.filters.http.custom_header_injection.v3";
option java_outer_classname = "CustomHeaderInjectionProto";
option java_multiple_files = true;
option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/filters/http/custom_header_injection/v3;custom_header_injectionv3";
option (udpa.annotations.file_status).package_version_status = ACTIVE;

// [#protodoc-title: Custom Header Injection]
// Custom header injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

// [#next-free-field: 4]
message CustomHeaderInjection {
  // Headers to inject in requests.
  map<string, string> request_headers = 1;

  // Headers to inject in responses.
  map<string, string> response_headers = 2;

  // Optional stat prefix for stats emission.
  string stat_prefix = 3;
}

#pragma once

#include <string>

#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"
#include "envoy/http/filter.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for the Custom Header Injection filter.
 */
class FilterConfig {
public:
  FilterConfig(
      const envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection&
          config);

  const std::map<std::string, std::string>& requestHeaders() const { return request_headers_; }
  const std::map<std::string, std::string>& responseHeaders() const { return response_headers_; }

private:
  const std::map<std::string, std::string> request_headers_;
  const std::map<std::string, std::string> response_headers_;
};

using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;

/**
 * HTTP Custom Header Injection filter. Injects configurable headers into requests and/or
 * responses.
 */
class CustomHeaderInjectionFilter : public Http::StreamDecoderFilter,
                                     public Http::StreamEncoderFilter,
                                     public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(FilterConfigSharedPtr config);

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override {
    return Http::FilterTrailersStatus::Continue;
  }

  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
    decoder_callbacks_ = &callbacks;
  }

  // Http::StreamEncoderFilter
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance& data, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap& trailers) override {
    return Http::FilterTrailersStatus::Continue;
  }

  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }

  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }

  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override {
    encoder_callbacks_ = &callbacks;
  }

  // Http::StreamFilterBase
  void onDestroy() override {}

private:
  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
  FilterConfigSharedPtr config_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

FilterConfig::FilterConfig(
    const envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection&
        config)
    : request_headers_(config.request_headers().begin(), config.request_headers().end()),
      response_headers_(config.response_headers().begin(), config.response_headers().end()) {}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(FilterConfigSharedPtr config)
    : config_(std::move(config)) {}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
                                                                    bool) {
  // Inject request headers
  for (const auto& [key, value] : config_->requestHeaders()) {
    headers.setCopy(Http::LowerCaseString(key), value);
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
                                                                    bool) {
  // Inject response headers
  for (const auto& [key, value] : config_->responseHeaders()) {
    headers.setCopy(Http::LowerCaseString(key), value);
  }
  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

