#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

class FilterTest : public testing::Test {
public:
  FilterTest() {
    envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection config;
    config.mutable_request_headers()->insert({"x-custom-request", "request-value"});
    config.mutable_response_headers()->insert({"x-custom-response", "response-value"});

    config_ = std::make_shared<FilterConfig>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_filter_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_filter_callbacks_);
  }

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_filter_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_filter_callbacks_;
  FilterConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
};

TEST_F(FilterTest, InjectRequestHeaders) {
  Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, true));
  EXPECT_EQ("request-value", request_headers.get_("x-custom-request"));
}

TEST_F(FilterTest, InjectResponseHeaders) {
  Http::TestResponseHeaderMapImpl response_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, true));
  EXPECT_EQ("response-value", response_headers.get_("x-custom-response"));
}

TEST_F(FilterTest, InjectMultipleHeaders) {
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection config;
  config.mutable_request_headers()->insert({"x-header-1", "value-1"});
  config.mutable_request_headers()->insert({"x-header-2", "value-2"});
  config.mutable_response_headers()->insert({"y-header-1", "response-1"});
  config.mutable_response_headers()->insert({"y-header-2", "response-2"});

  auto filter_config = std::make_shared<FilterConfig>(config);
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(filter_config);
  filter->setDecoderFilterCallbacks(decoder_filter_callbacks_);
  filter->setEncoderFilterCallbacks(encoder_filter_callbacks_);

  // Test request headers
  Http::TestRequestHeaderMapImpl request_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));
  EXPECT_EQ("value-1", request_headers.get_("x-header-1"));
  EXPECT_EQ("value-2", request_headers.get_("x-header-2"));

  // Test response headers
  Http::TestResponseHeaderMapImpl response_headers{};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter->encodeHeaders(response_headers, true));
  EXPECT_EQ("response-1", response_headers.get_("y-header-1"));
  EXPECT_EQ("response-2", response_headers.get_("y-header-2"));
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

